  children.push(heading1("\u7AE0\u7BC0\u56DB\u3001\u6E2C\u8A66\u65B9\u6CD5\u8207\u6280\u8853\u67B6\u69CB"));
  children.push(heading2("4.1 \u6A21\u578B\u904B\u7B97\u6D41\u7A0B"));
  children.push(body("MCLUB \u532F\u7387\u58D3\u529B\u6E2C\u8A66\u63A1\u7528\u4E94\u6B65\u6A21\u578B\u904B\u7B97\u6D41\u7A0B\uFF0C\u5F9E\u8CC7\u6599\u63A1\u96C6\u5230\u6700\u7D42\u5831\u544A\u7522\u51FA\uFF0C\u6BCF\u500B\u6B65\u9A5F\u5747\u6709\u56B4\u683C\u7684\u8CE6\u8B49\u6A5F\u5236\u3002\u7B2C\u4E00\u6B65\u70BA\u8CC7\u7522\u8CC7\u6599\u63A1\u96C6\uFF0C\u5305\u62EC\u5BA2\u6236\u7684\u591A\u5E63\u5225\u8CC7\u7522\u6E05\u55AE\u3001\u5404\u9805\u8CC7\u7522\u7684\u5E63\u5225\u6B78\u5C6C\u3001\u540D\u7FA9\u50F9\u503C\u3001\u6210\u672C\u50F9\u503C\u3001\u5230\u671F\u65E5\u7B49\u8CC7\u8A0A\u3002\u7B2C\u4E8C\u6B65\u70BA\u60C5\u5883\u53C3\u6578\u8A2D\u5B9A\uFF0C\u6839\u64DA\u5BA2\u6236\u6301\u6709\u7684\u5E63\u5225\u7D44\u5408\uFF0C\u5C07\u5404\u60C5\u5883\u7684\u532F\u7387\u8B8A\u52D5\u5206\u914D\u81F3\u5C0D\u61C9\u7684\u5E63\u5C0D\u3002\u7B2C\u4E09\u6B65\u70BA\u8CC7\u7522\u91CD\u4F30\uFF0C\u4F7F\u7528\u60C5\u5883\u532F\u7387\u5C0D\u6BCF\u9805\u8CC7\u7522\u9032\u884C\u91CD\u65B0\u8A08\u50F9\u3002\u7B2C\u56DB\u6B65\u70BA\u640D\u76CA\u8A08\u7B97\uFF0C\u6BD4\u8F03\u57FA\u6E96\u60C5\u5883\u8207\u5404\u58D3\u529B\u60C5\u5883\u4E0B\u7684\u8CC7\u7522\u50F9\u503C\u5DEE\u7570\u3002\u7B2C\u4E94\u6B65\u70BA\u5831\u544A\u7522\u51FA\uFF0C\u5C07\u5206\u6790\u7D50\u679C\u7D44\u7E54\u70BA\u7D50\u69CB\u5316\u5831\u544A\uFF0C\u5305\u542B\u5EFA\u8B70\u8207\u884C\u52D5\u65B9\u6848\u3002"));
  children.push(body("\u6BCF\u500B\u6B65\u9A5F\u7684\u8CE6\u8B49\u6A5F\u5236\u5305\u62EC\uFF1A\u8CC7\u6599\u63A1\u96C6\u968E\u6BB5\u7684\u96D9\u91CD\u8F38\u5165\u9A57\u8B49\uFF08\u5BA2\u6236\u78BA\u8A8D + \u5206\u6790\u5E2B\u5FA9\u6838\uFF09\uFF0C\u60C5\u5883\u53C3\u6578\u8A2D\u5B9A\u7684\u5408\u7406\u6027\u5BE9\u67E5\uFF08\u53C3\u8003\u6B77\u53F2\u6578\u64DA\u8207\u76E3\u7BA1\u6307\u5F15\uFF09\uFF0C\u4EE5\u53CA\u6700\u7D42\u5831\u544A\u7684\u5167\u90E8\u8CE6\u8B49\u5BA9\u6838\u3002\u9019\u7A2E\u56B4\u683C\u7684\u8CE6\u8B49\u6D41\u7A0B\u78BA\u4FDD\u4E86\u5831\u544A\u7684\u6E96\u78BA\u6027\u548C\u53EF\u4FE1\u6027\uFF0C\u80FD\u5920\u7D93\u53D7\u4FE1\u8A17\u5BE9\u8A08\u548C\u76E3\u7BA1\u5BE9\u67E5\u7684\u6AA2\u9A57\u3002"));

  children.push(heading2("4.2 \u8CC7\u7522\u8986\u84CB\u7BC4\u570D"));
  children.push(body("\u58D3\u529B\u6E2C\u8A66\u7684\u8CC7\u7522\u8986\u84CB\u7BC4\u570D\u5305\u62EC\u5BA2\u6236\u6301\u6709\u7684\u6240\u6709\u53D7\u532F\u7387\u5F71\u97FF\u7684\u8CC7\u7522\u985E\u5225\uFF0C\u4E3B\u8981\u5206\u70BA\u4EE5\u4E0B\u516D\u5927\u985E\u5225\u3002\u7B2C\u4E00\u985E\u662F\u73FE\u91D1\u8207\u5B58\u6B3E\uFF0C\u5305\u62EC\u591A\u5E63\u5225\u9280\u884C\u5B58\u6B3E\u3001\u5B9A\u671F\u5B58\u6B3E\u53CA\u73FE\u91D1\u7B49\u50F9\u503C\u7269\uFF0C\u5176\u532F\u7387\u98A8\u96AA\u66B4\u9732\u76F4\u63A5\u4E14\u7ACB\u5373\u3002\u7B2C\u4E8C\u985E\u662F\u5B9A\u606F\u8B49\u5238\uFF0C\u5305\u62EC\u5404\u5E63\u5225\u653F\u5E9C\u50B5\u5238\u3001\u516C\u53F8\u50B5\u5238\u53CA\u53EF\u8F49\u63DB\u50B5\u5238\uFF0C\u5176\u50F9\u503C\u53D7\u532F\u7387\u8207\u5229\u7387\u8B8A\u52D5\u96D9\u91CD\u5F71\u97FF\u3002\u7B2C\u4E09\u985E\u662F\u80A1\u6B0A\u8B66\u5225\u6295\u8CC7\uFF0C\u5305\u62EC\u5883\u5167\u5916\u80A1\u7968\u3001ETF \u53CA\u79C1\u52DF\u57FA\u91D1\uFF0C\u5176\u532F\u7387\u5F71\u97FF\u900F\u904E\u8A72\u5E63\u5225\u8CC7\u7522\u7684\u672C\u5E63\u8A08\u50F9\u4F86\u50B3\u5C0E\u3002\u7B2C\u56DB\u985E\u662F\u4E0D\u52D5\u7522\u8207\u7269\u696D\u6295\u8CC7\uFF0C\u5305\u62EC\u6D77\u5916\u7269\u696D\u3001\u65E5\u672C\u7269\u696D\u7B49\uFF0C\u79DF\u91D1\u6536\u5165\u8207\u8CC7\u7522\u50F9\u503C\u5747\u53D7\u532F\u7387\u5F71\u97FF\u3002\u7B2C\u4E94\u985E\u662F\u5916\u532F\u884D\u751F\u7522\u54C1\uFF0C\u5305\u62EC\u904E\u671F\u5408\u7D04\u3001\u532F\u7387\u671F\u6B0A\u3001\u8CA8\u5E63\u4EA4\u63DB\u7B49\uFF0C\u9019\u4E9B\u7522\u54C1\u7684\u532F\u7387\u654F\u611F\u5EA6\u6700\u9AD8\u3002\u7B2C\u516D\u985E\u662F\u8DE8\u5883\u61C9\u6536\u61C9\u4ED8\u5E33\u6B3E\uFF0C\u5305\u62EC\u591A\u5E63\u5225\u61C9\u6536\u5E33\u6B3E\u3001\u61C9\u4ED8\u5E33\u6B3E\u53CA\u8DE8\u5883\u5206\u516C\u53F8\u5F80\u4F86\uFF0C\u5176\u532F\u7387\u5F71\u97FF\u53D6\u6C7A\u65BC\u5E63\u7A2E\u932F\u914D\u7A0B\u5EA6\u3002"));

  children.push(heading2("4.3 \u6280\u8853\u5BE6\u73FE\u65B9\u5F0F"));
  children.push(body("\u5728\u6280\u8853\u5BE6\u73FE\u5C64\u9762\uFF0CMCLUB \u63A1\u7528\u300C\u532F\u7387\u654F\u611F\u5EA6\u5206\u6790 + \u60C5\u5883\u6A21\u64EC\u300D\u7684\u96D9\u8F09\u65B9\u6CD5\u3002\u532F\u7387\u654F\u611F\u5EA6\u5206\u6790\uFF08FX Sensitivity Analysis\uFF09\u8A08\u7B97\u6BCF\u9805\u8CC7\u7522\u5C0D\u532F\u7387\u8B8A\u52D5 1% \u7684\u50F9\u503C\u8B8A\u5316\uFF08Delta\uFF09\uFF0C\u5F62\u6210\u654F\u611F\u5EA6\u77E9\u65B7\uFF0C\u8B93\u5206\u6790\u5E2B\u5FEB\u901F\u8B58\u5225\u98A8\u96AA\u96C6\u4E2D\u9EDE\u3002\u60C5\u5883\u6A21\u64EC\u5247\u5C07\u60C5\u5883\u532F\u7387\u61C9\u7528\u65BC\u5BE6\u969B\u8CC7\u7522\u7D44\u5408\uFF0C\u8A08\u7B97\u5404\u60C5\u5883\u4E0B\u7684\u8CC7\u7522\u6DF7\u5408\u50F9\u503C\u3002\u5169\u7A2E\u65B9\u6CD5\u7D50\u5408\u4F7F\u7528\uFF0C\u65E2\u80FD\u63D0\u4F9B\u5FAE\u89C0\u5C64\u9762\u7684\u654F\u611F\u5EA6\u8CC7\u8A0A\uFF0C\u53C8\u80FD\u63D0\u4F9B\u5B8F\u89C0\u5C64\u9762\u7684\u60C5\u5883\u640D\u76CA\u6578\u64DA\uFF0C\u5F62\u6210\u5B8C\u6574\u7684\u5206\u6790\u5716\u666F\u3002"));
  children.push(body("\u5C0D\u65BC\u7279\u5B9A\u985E\u578B\u7684\u8CC7\u7522\uFF0C\u6211\u5011\u9084\u63A1\u7528\u66F4\u7CBE\u7D30\u7684\u8A08\u50F9\u6A21\u578B\u3002\u4F8B\u5982\uFF0C\u5C0D\u65BC\u542B\u532F\u7387\u884D\u751F\u7522\u54C1\u7684\u8CC7\u7522\uFF0C\u4F7F\u7528 Black-Scholes \u6216 Garman-Kohlhagen \u6A21\u578B\u9032\u884C\u91CD\u4F30\uFF1B\u5C0D\u65BC\u4E0D\u52D5\u7522\u6295\u8CC7\uFF0C\u8003\u616E\u79DF\u91D1\u6536\u5165\u7684\u532F\u7387\u8F49\u63DB\u5F71\u97FF\u53CA\u8CC7\u672C\u5316\u7387\u8B8A\u52D5\uFF1B\u5C0D\u65BC\u8DE8\u5883\u61C9\u6536\u61C9\u4ED8\u5E33\u6B3E\uFF0C\u8003\u616E\u7D50\u7B97\u6642\u9593\u5DEE\u7570\u5E36\u4F86\u7684\u532F\u7387\u98A8\u96AA\u65B7\u53E3\u3002\u6BCF\u7A2E\u8CC7\u7522\u985E\u578B\u7684\u8A08\u50F9\u65B9\u6CD5\u5747\u5728\u5831\u544A\u4E2D\u660E\u78BA\u62AB\u9732\uFF0C\u78BA\u4FDD\u900F\u660E\u5EA6\u548C\u53EF\u5BE9\u8A08\u6027\u3002"));

  // Chapter 5: Service Deliverables
  children.push(heading1("\u7AE0\u7BC0\u4E94\u3001\u670D\u52D9\u5167\u5BB9\u8207\u4EA4\u4ED8\u7269"));
  children.push(heading2("5.1 \u670D\u52D9\u6D41\u7A0B"));
  children.push(body("MCLUB \u532F\u7387\u58D3\u529B\u6E2C\u8A66\u5831\u544A\u7684\u670D\u52D9\u6D41\u7A0B\u5206\u70BA\u56DB\u500B\u968E\u6BB5\uFF0C\u5F9E\u521D\u6B65\u63A5\u89F8\u5230\u6700\u7D42\u4EA4\u4ED8\uFF0C\u6BCF\u500B\u968E\u6BB5\u5747\u6709\u660E\u78BA\u7684\u5DE5\u4F5C\u5167\u5BB9\u548C\u6642\u9593\u7BC0\u9EDE\u3002\u7B2C\u4E00\u968E\u6BB5\u70BA\u9700\u6C42\u8A3A\u65B7\uFF08Week 1\uFF09\uFF0C\u8207\u5BA2\u6236\u9032\u884C\u6DF1\u5EA6\u8A3A\u65B7\uFF0C\u4E86\u89E3\u8CC7\u7522\u7D44\u5408\u7D50\u69CB\u3001\u5E63\u5225\u66B4\u9732\u3001\u98A8\u96AA\u504F\u597D\u53CA\u7279\u6B8A\u95DC\u6CE8\u9EDE\u3002\u7B2C\u4E8C\u968E\u6BB5\u70BA\u8CC7\u6599\u63A1\u96C6\u8207\u6E2C\u8A66\u57F7\u884C\uFF08Week 2\u20133\uFF09\uFF0C\u6536\u96C6\u5BA2\u6236\u8CC7\u7522\u6578\u64DA\uFF0C\u8A2D\u5B9A\u60C5\u5883\u53C3\u6578\uFF0C\u57F7\u884C\u58D3\u529B\u6E2C\u8A66\u6A21\u578B\u3002\u7B2C\u4E09\u968E\u6BB5\u70BA\u7D50\u679C\u5BE9\u8996\u8207\u5831\u544A\u64B0\u5BEB\uFF08Week 3\u20134\uFF09\uFF0C\u5C0D\u6E2C\u8A66\u7D50\u679C\u9032\u884C\u5167\u90E8\u5BE9\u8996\uFF0C\u64B0\u5BEB\u6B63\u5F0F\u5831\u544A\u4E26\u88FD\u5B9A\u5EFA\u8B70\u3002\u7B2C\u56DB\u968E\u6BB5\u70BA\u5831\u544A\u4EA4\u4ED8\u8207\u89E3\u8B80\uFF08Week 4\uFF09\uFF0C\u5411\u5BA2\u6236\u6B63\u5F0F\u4EA4\u4ED8\u5831\u544A\uFF0C\u9032\u884C\u8A73\u7D30\u89E3\u8B80\u4E26\u8A0E\u8AD6\u5F8C\u7E8C\u884C\u52D5\u65B9\u6848\u3002"));

